const adminUrl=window.location.href.replace("auth-frame/","")+"api/admin",siteOrigin="https://blog.ybyracasting.com";window.addEventListener("message",async function(t){if(t.origin!==siteOrigin)return void console.warn("Ignored message to admin auth iframe because of mismatch in origin","expected",siteOrigin,"got",t.origin,"with data",t.data);let n=null;try{n=JSON.parse(t.data)}catch(t){console.error(t)}function i(i,a){t.source.postMessage(JSON.stringify({uid:n.uid,error:i,result:a}),siteOrigin)}if("browseComments"===n.action)try{const{postId:t,params:a}=n,e=await fetch(adminUrl+`/comments/post/${t}/?${new URLSearchParams(a).toString()}`);i(null,await e.json())}catch(t){i(t,null)}if("getReplies"===n.action)try{const{commentId:t,params:a}=n,e=await fetch(adminUrl+`/comments/${t}/replies/?${new URLSearchParams(a).toString()}`);i(null,await e.json())}catch(t){i(t,null)}if("readComment"===n.action)try{const{commentId:t,params:a}=n,e=await fetch(adminUrl+"/comments/"+t+"/?"+new URLSearchParams(a).toString());i(null,await e.json())}catch(t){i(t,null)}if("getUser"===n.action)try{const t=await fetch(adminUrl+"/users/me/?include=roles");i(null,await t.json())}catch(t){i(t,null)}if("hideComment"===n.action)try{const t=await fetch(adminUrl+"/comments/"+n.id+"/",{method:"PUT",body:JSON.stringify({comments:[{id:n.id,status:"hidden"}]}),headers:{"Content-Type":"application/json"}});i(null,await t.json())}catch(t){i(t,null)}if("showComment"===n.action)try{const t=await fetch(adminUrl+"/comments/"+n.id+"/",{method:"PUT",body:JSON.stringify({comments:[{id:n.id,status:"published"}]}),headers:{"Content-Type":"application/json"}});i(null,await t.json())}catch(t){i(t,null)}});